gtag('config', 'G-BCFW0167Q0');

// Send author as a custom parameter in page_view
gtag('event', 'page_view', {
  author: "Unknown Author"  });

    window.googletag = window.googletag || { cmd: [] };

googletag.cmd.push(function () {
  // Standard ad slots
