  googletag.defineSlot('/21835567781/rgk_300x250', [300, 250], 'div-gpt-ad-300x250').addService(googletag.pubads());
  googletag.defineSlot('/21835567781/rgk_300x50', [300, 50], 'div-gpt-ad-300x50').addService(googletag.pubads());
  googletag.defineSlot('/21835567781/rgk_728x90', [728, 90], 'div-gpt-ad-728x90').addService(googletag.pubads());

  // Out-of-Page slot (e.g. roadblock/screen takeover)
