div.script:
        document.addEventListener('DOMContentLoaded', function(){
    const ytBtn = document.getElementById('yt-placeholder');
    const watchPane = document.getElementById('watch-pane');
    const listenPane = document.getElementById('listen-pane');
    const tabWatch = document.getElementById('tab-watch');
    const tabListen = document.getElementById('tab-listen');

    // Tabs (if audio present)
    function activatePane(btn, pane){
        [tabWatch, tabListen].filter(Boolean).forEach(b=>{
            if(!b) return; b.classList.toggle('btn-dark', b===btn);
            b.classList.toggle('btn-outline-dark', b!==btn);
            b.setAttribute('aria-selected', b===btn ? 'true' : 'false');
        });
        [watchPane, listenPane].filter(Boolean).forEach(p=>{
            if(!p) return; p.classList.toggle('active', p===pane);
        });
        // Pause audio when switching to video
        if (pane === watchPane && listenPane){
            const audio = document.getElementById('rgk-audio');
            if (audio && !audio.paused) audio.pause();
        }
    }
    if (tabWatch && tabListen){
        tabWatch.addEventListener('click', ()=>activatePane(tabWatch, watchPane));
        tabListen.addEventListener('click', ()=>activatePane(tabListen, listenPane));
    }

    // Click-to-play for YouTube (better LCP & CLS)
    if (ytBtn){
        ytBtn.addEventListener('click', function(){
            const src = this.dataset.src;
            const title = this.dataset.title || 'Live video';
            const iframe = document.createElement('iframe');
            iframe.width = '100%';
            iframe.height = '100%';
            iframe.src = src;
            iframe.title = title;
            iframe.allow = 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share';
            iframe.allowFullscreen = true;
            iframe.loading = 'eager';
            this.replaceWith(iframe);
            setupMiniPlayer(iframe);
        }, { once: true });
    } else {
        // Twitch embed init
        if (document.getElementById('twitch-embed') && window.Twitch){
            new Twitch.Player("twitch-embed", {
                channel: "radiogenke",
                width: "100%",
                height: "100%",
                parent: [window.location.hostname]
            });
        } else {
            // Load Twitch SDK lazily if not present
            const s = document.createElement('script');
            s.src = "https://player.twitch.tv/js/embed/v1.js"; s.async = true;
            s.onload = ()=> {
                new Twitch.Player("twitch-embed", {
                    channel: "radiogenke",
                    width: "100%",
                    height: "100%",
                    parent: [window.location.hostname]
                });
            };
            document.getElementById('twitch-wrap')?.appendChild(s);
        }
    }

    // Sticky mini-player when scrolled past (desktop only)
    function setupMiniPlayer(iframe){
        if (window.matchMedia('(max-width: 991.98px)').matches) return; // desktop only
        const playerFrame = document.querySelector('.live-hero .player-frame');
        if (!playerFrame) return;

        const mini = document.createElement('div');
        mini.className = 'mini-player';
        mini.style.display = 'none';
        const close = document.createElement('button');
        close.className = 'mini-close';
        close.setAttribute('aria-label', 'Close mini player');
        close.textContent = '×';

        const miniIframe = iframe.cloneNode(true);
        mini.appendChild(miniIframe);
        mini.appendChild(close);
        document.body.appendChild(mini);

        close.addEventListener('click', ()=>{ mini.remove(); observer.disconnect(); });

        const observer = new IntersectionObserver(entries=>{
            entries.forEach(entry=>{
                // When main player is < 20% visible, show mini
                if(entry.intersectionRatio < 0.2){
                    mini.style.display = 'block';
                } else {
                    mini.style.display = 'none';
                }
            });
        }, { threshold:[0, .2, 1] });

        observer.observe(playerFrame);
    }
});

body.script:
    window.googletag = window.googletag || { cmd: [] };
googletag.cmd.push(() => {
  // Enable video ads and define the bottom anchor ad slot.
  googletag.pubads().enableVideoAds();

  const anchorAdSlot = googletag.defineOutOfPageSlot(
    '/21835567781/rgk_anchor_ad',
    googletag.enums.OutOfPageFormat.BOTTOM_ANCHOR
  )?.addService(googletag.pubads());

  googletag.enableServices();

  if (anchorAdSlot) {
    googletag.display(anchorAdSlot.getSlotElementId());
  }
});

      (function(){
  const root   = document.getElementById('rgk-radio');
  const fab    = document.getElementById('rgk-radio-fab');
  const panel  = document.getElementById('rgk-radio-panel');
  const closeB = document.getElementById('rgk-radio-close');
  const audio  = document.getElementById('rgk-radio-audio');

  if(!root || !fab || !panel || !audio) return;

  // Toggle helpers
  function expand(){
    root.setAttribute('data-state','expanded');
    fab.setAttribute('aria-expanded','true');
    panel.style.display = 'block';
  }
  function collapse(){
    root.setAttribute('data-state','collapsed');
    fab.setAttribute('aria-expanded','false');
    panel.style.display = 'none';
  }

  // Click FAB to open/close
  fab.addEventListener('click', ()=>{
    const expanded = root.getAttribute('data-state') === 'expanded';
    expanded ? collapse() : expand();
  });

  // Close button
  closeB?.addEventListener('click', collapse);

  // Close on ESC
  document.addEventListener('keydown', (e)=>{
    if(e.key === 'Escape'){ collapse(); }
  });

  // Close when clicking outside panel (but not FAB)
  document.addEventListener('click', (e)=>{
    if(!panel.contains(e.target) && !fab.contains(e.target)){
      collapse();
    }
  });

  // Equalizer state (shows on FAB when playing)
  function updatePlayingState(){
    if(!audio.paused && !audio.ended && audio.currentTime > 0){
      root.classList.add('is-playing');
    } else {
      root.classList.remove('is-playing');
    }
  }
  audio.addEventListener('play', updatePlayingState);
  audio.addEventListener('pause', updatePlayingState);
  audio.addEventListener('ended', updatePlayingState);
  audio.addEventListener('timeupdate', updatePlayingState);

  // Optional: remember if user left it open (comment out if not needed)
  const lastState = sessionStorage.getItem('rgk-radio-state');
  if(lastState === 'expanded') expand();
  new MutationObserver(()=>{
    sessionStorage.setItem('rgk-radio-state', root.getAttribute('data-state'));
  }).observe(root, { attributes:true, attributeFilter:['data-state'] });

})();

  function cleanOldServiceWorkers() {
    const CLEANUP_DATE = new Date('2025-03-17T14:44:00Z'); // UTC Time

    if ('serviceWorker' in navigator) {
        navigator.serviceWorker.getRegistrations().then(registrations => {
            registrations.forEach(registration => {
                // Check registration time (fallback to now if not available)
                const installTime = new Date(registration.installing?.scriptURL || registration.active?.scriptURL || Date.now());

                if (installTime < CLEANUP_DATE) {
                    console.log('Service Worker registered before cleanup date, unregistering...');

                    registration.unregister().then(() => {
                        console.log('Old Service Worker unregistered.');

                        // Clear any local subscription data to ensure resubscription
                        localStorage.removeItem('pushPromptShown');
                    });
                } else {
                    console.log('Service Worker is up-to-date and does not need unregistering.');
                }
            });
        }).catch(error => {
            console.error('Error fetching service worker registrations:', error);
        });
    } else {
        console.warn('Service Workers are not supported in this browser.');
    }
}

cleanOldServiceWorkers();

      document.addEventListener("DOMContentLoaded", () => {
        const modal = document.getElementById("pushNotificationModal");
        const pushAccept = document.getElementById("pushAccept");
        const pushDecline = document.getElementById("pushDecline");

        // Show modal after delay if user hasn't been prompted
        // setTimeout(() => {
        //     if (!localStorage.getItem("pushPromptShown") && Notification.permission === "default") {
        //         modal.style.display = "flex"; // Show the modal
        //     }
        // }, 2000);


      const isBot = /googlebot|bingbot|slurp|duckduckbot/i.test(navigator.userAgent);
if (!isBot) {
    setTimeout(() => {
        if (!localStorage.getItem("pushPromptShown") && Notification.permission === "default") {
            modal.style.display = "flex"; // Show modal after 30s
        }
    }, 30000); // 30,000 ms = 30 seconds
}


        // Handle "Yes, Thanks" button click
        pushAccept.addEventListener("click", () => {
            console.log("User clicked 'Yes, Thanks'.");
            Notification.requestPermission()
                .then((permission) => {
                    console.log(`Notification permission: ${permission}`);
                    if (permission === "granted") {
                        // localStorage.setItem("pushPromptShown", "true");
                        localStorage.setItem("pushPromptShown", Date.now());
                        subscribeToPushNotifications();
                    }
                })
                .catch((error) => console.error("Error requesting notification permission:", error));
            modal.style.display = "none"; // Hide the modal
        });

        // Handle "No" button click
        pushDecline.addEventListener("click", () => {
            console.log("User declined push notifications.");
            // localStorage.setItem("pushPromptShown", "true");
            localStorage.setItem("pushPromptShown", Date.now());
            modal.style.display = "none"; // Hide the modal
        });

        if (Notification.permission === "granted") {
            navigator.serviceWorker.ready.then(reg => {
                reg.pushManager.getSubscription().then(sub => {
                    if (!sub) {
                        subscribeToPushNotifications();
                    } else {
                        console.log("✅ Already subscribed:", sub);
                    }
                });
            });
        }

        // 🔐 ESC key closes modal
        document.addEventListener("keydown", (e) => {
            if (e.key === "Escape") {
                modal.style.display = "none";
                // localStorage.setItem("pushPromptShown", "true");
                localStorage.setItem("pushPromptShown", Date.now());
            }
        });
    });






    function subscribeToPushNotifications() {
        if (!("serviceWorker" in navigator)) {
            console.error("Service Workers are not supported in this browser.");
            return;
        }
        if (!("PushManager" in window)) {
            console.error("Push Notifications are not supported in this browser.");
            return;
        }

        navigator.serviceWorker.ready.then((registration) => {
            const applicationServerKey = urlBase64ToUint8Array(
                "BG0KsmwktWW82Vz4VGraLxqKd0lHjdx7ATE8G2DQG8mwXS4sEUXD8W2KI9PKoPnqyhCCXeAtoNkjhjbCS_Ql1FI"
            );

            registration.pushManager
                .subscribe({
                    userVisibleOnly: true,
                    applicationServerKey,
                })
                .then((subscription) => {
                    console.log("User subscribed:", subscription);

                    const payload = {
                        subscription,
                        content_encoding: "aes128gcm",
                    };

                    // Send subscription to backend

                    fetch(`/push-subscription`, {
                            method: "POST",
                            headers: {
                                "Content-Type": "application/json",
                                "X-CSRF-TOKEN": document.querySelector('meta[name="csrf-token"]').getAttribute("content"),
                            },
                            body: JSON.stringify(payload),
                        })
                        .then((response) => {
                            if (!response.ok) {
                                return response.json().then((error) => {
                                    console.error("Failed to save subscription:", error);
                                });
                            }
                            console.log("Subscription saved successfully!");
                        })
                        .catch((error) => console.error("Fetch error:", error));
                })
                .catch((error) => {
                    if (error.name === "NotAllowedError") {
                        console.error("Push subscription failed: User denied permissions.");
                    } else if (error.name === "AbortError") {
                        console.error("Push subscription failed: Operation aborted.");
                    } else {
                        console.error("Push subscription failed:", error);
                    }
                });
        });
    }

    // Utility: Convert VAPID key to Uint8Array
    function urlBase64ToUint8Array(base64String) {
        const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
        const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
        const rawData = window.atob(base64);
        const outputArray = new Uint8Array(rawData.length);
        for (let i = 0; i < rawData.length; ++i) {
            outputArray[i] = rawData.charCodeAt(i);
        }
        return outputArray;
    }

  const SW_NAME = "MuGeraPushNotifications";

if ("serviceWorker" in navigator && "PushManager" in window) {
    const cacheBuster = "002" + new Date().getTime();

    // Register the service worker
    navigator.serviceWorker
        .register(`/sw.js?${cacheBuster}`)
        .catch(() => {}); // Silently handle registration errors



    // Listen for messages from the Service Worker
    navigator.serviceWorker.addEventListener("message", (event) => {
        if (event.data && event.data.type === "trackPageView") {
            let authorName = document.querySelector('meta[name="author"]')?.getAttribute("content") || "Unknown Author";
            let pageUrl = event.data.url || window.location.href;

            if (!window.__gaPageViewSent) { // Prevent duplicate tracking
                console.log("Tracking GA4 Page View:", pageUrl);
                gtag("event", "page_view", {
                    page_title: document.title,
                    page_location: pageUrl,
                    author: authorName
                });
                window.__gaPageViewSent = true; // Mark as sent
            } else {
                console.warn("Duplicate GA4 Page View blocked:", pageUrl);
            }
        }
    });



    // Track PWA Standalone Mode Views with Author
    function trackStandaloneView() {
        if (
            window.matchMedia('(display-mode: standalone)').matches ||
            window.navigator.standalone === true // iOS Safari standalone mode
        ) {
            // Get author name from meta tag
            let authorName = document.querySelector('meta[name="author"]')?.getAttribute("content") || "Unknown Author";

            // Send GA4 event for PWA installed view
            gtag('event', 'pwa_installed_view', {
                page_title: document.title,
                page_location: window.location.href,
                author: authorName
            });
        }
    }

    // Check if running in PWA mode on page load
    trackStandaloneView();

    // Also track when visibility changes (e.g., user switches back to PWA)
    document.addEventListener("visibilitychange", () => {
        if (document.visibilityState === "visible") {
            trackStandaloneView();
        }
    });
}
